import logging
import os
import stat
from logging.handlers import RotatingFileHandler

def setup_logging(log_directory='/var/log/myapp', log_filename='app.log', max_bytes=10485760, backup_count=5):
    # Create log directory if it doesn't exist
    os.makedirs(log_directory, exist_ok=True)
    
    # Set permissions for log directory
    os.chmod(log_directory, stat.S_IRWXU | stat.S_IRGRP | stat.S_IXGRP | stat.S_IROTH | stat.S_IXOTH)
    
    # Create full log file path
    log_file_path = os.path.join(log_directory, log_filename)
    
    # Create logger
    logger = logging.getLogger('MyApp')
    logger.setLevel(logging.DEBUG)
    
    # Create rotating file handler
    handler = RotatingFileHandler(
        log_file_path,
        maxBytes=max_bytes,
        backupCount=backup_count
    )
    
    # Set log format
    formatter = logging.Formatter(
        '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
    )
    handler.setFormatter(formatter)
    
    # Add handler to logger
    logger.addHandler(handler)
    
    # Set file permissions for log file
    os.chmod(log_file_path, stat.S_IRUSR | stat.S_IWUSR | stat.S_IRGRP | stat.S_IROTH)
    
    return logger

# Usage example
if __name__ == "__main__":
    logger = setup_logging()
